<template>
  <view class="privacy-modal" v-if="show">
    <view class="privacy-content">
      <text class="privacy-title">隐私保护指引</text>
      <view class="privacy-desc">
        在使用本小程序服务之前，请您务必仔细阅读并同意<text class="privacy-link" @click="openPrivacyContract">{{privacyContractName}}</text>。当您点击同意并继续时，即表示您已理解并同意该指引内容。
      </view>
      <view class="privacy-actions">
        <button class="privacy-btn reject" @click="handleReject">不同意</button>
        <button 
          class="privacy-btn agree" 
          open-type="agreePrivacyAuthorization" 
          @agreeprivacyauthorization="handleAgree"
        >同意并继续</button>
      </view>
    </view>
  </view>
</template>

<script setup>
import { ref, onMounted } from 'vue';

const show = ref(false);
const privacyContractName = ref('《用户隐私保护指引》');
let resolvePrivacyAuthorization = null;

onMounted(() => {
  // 检查是否需要隐私授权
  if (uni.getPrivacySetting) {
    uni.getPrivacySetting({
      success: (res) => {
        if (res.needAuthorization) {
          privacyContractName.value = res.privacyContractName || '《用户隐私保护指引》';
          // 可以在这里决定是否主动弹出，或者等待触发
        }
      }
    });
  }

  // 监听隐私授权请求
  if (uni.onNeedPrivacyAuthorization) {
    uni.onNeedPrivacyAuthorization((resolve) => {
      show.value = true;
      resolvePrivacyAuthorization = resolve;
    });
  }
});

const openPrivacyContract = () => {
  uni.openPrivacyContract({
    fail: () => {
      uni.showToast({ title: '无法打开隐私协议', icon: 'none' });
    }
  });
};

const handleAgree = () => {
  show.value = false;
  if (resolvePrivacyAuthorization) {
    resolvePrivacyAuthorization({ buttonId: 'agree-btn', event: 'agree' });
    resolvePrivacyAuthorization = null;
  }
};

const handleReject = () => {
  show.value = false;
  uni.showToast({ title: '拒绝隐私协议将无法使用部分功能', icon: 'none' });
  if (resolvePrivacyAuthorization) {
    resolvePrivacyAuthorization({ event: 'disagree' });
    resolvePrivacyAuthorization = null;
  }
};

// 暴露给父组件的主动检查方法
const check = () => {
  if (uni.getPrivacySetting) {
    uni.getPrivacySetting({
      success: (res) => {
        if (res.needAuthorization) {
          privacyContractName.value = res.privacyContractName || '《用户隐私保护指引》';
          show.value = true;
        }
      }
    });
  }
};

defineExpose({ check });
</script>

